const fs = require('fs');

function readLogFile(filename) {
  const filePath = `${process.cwd()}/${filename}`;
  try {
    const data = fs.readFileSync(filePath, 'utf8');
    return data;
  } catch (err) {
    console.error(`Error reading log file: ${err.message}`);
    return null;
  }
}